12→  --color-text-primary: #1A1D23;
13→  --color-text-secondary: #5F6470;
14→  --color-text-tertiary: #9CA3AF;
15→  --color-panel-bg: #F3F3F0;
16→  --color-panel-bg-alt: #FAFAF8;
