 1→@import './reset.css';
 2→@import './variables.css';
 3→
 4→html, body, #root {
 5→  height: 100%;
 6→  width: 100%;
 7→  overflow: hidden;
 8→}
 9→
10→body {
11→  font-family: var(--font-ui);
12→  font-size: 13px;
13→  color: var(--color-text-primary);
14→  background: var(--color-background);
15→  -webkit-font-smoothing: antialiased;
16→  text-rendering: optimizeLegibility;
17→}
18→
19→/* Custom scrollbars */
20→::-webkit-scrollbar {
21→  width: 6px;
22→  height: 6px;
23→}
24→
25→::-webkit-scrollbar-track {
26→  background: transparent;
27→}
28→
29→::-webkit-scrollbar-thumb {
30→  background: rgba(0, 0, 0, 0.15);
31→  border-radius: 3px;
32→}
33→
34→::-webkit-scrollbar-thumb:hover {
35→  background: rgba(0, 0, 0, 0.25);
36→}
37→
38→/* Selection highlight */
39→::selection {
40→  background: rgba(13, 124, 102, 0.15);
41→}
42→
43→/* Focus ring */
44→:focus-visible {
45→  outline: 2px solid var(--color-accent);
46→  outline-offset: 1px;
