73→
74→@keyframes fadeInUp {
75→  from {
76→    opacity: 0;
77→    transform: translateY(4px);
78→  }
79→  to {
80→    opacity: 1;
81→    transform: translateY(0);
82→  }
83→}
84→
85→@keyframes pulse {
86→  0%, 100% { opacity: 1; }
87→  50% { opacity: 0.5; }
